        "github.com/submariner-io/submariner/pkg/event"
)

type contextAwareHandler struct {
        event.HandlerBase
}

func (h *contextAwareHandler) GetName() string { return "context-aware" }
func (h *contextAwareHandler) GetNetworkPlugins() []string { return []string{event.AnyNetworkPlugin} }
func (h *contextAwareHandler) Stop(ctx context.Context) error { return ctx.Err() }
func (h *contextAwareHandler) Uninstall(ctx context.Context) error { return ctx.Err() }

var _ event.Handler = &contextAwareHandler{}

func main() {
        ctx := context.Background()
        registry, err := event.NewRegistry(ctx, "repro", event.AnyNetworkPlugin, &contextAwareHandler{})
        if err != nil {
                panic(err)
        }
        if err := registry.StopHandlers(ctx); err != nil {
                panic(err)
        }
        if err := registry.Uninstall(ctx); err != nil {
                panic(err)
        }
}
