package main

import (
        "context"
        "strings"

        "github.com/submariner-io/submariner/pkg/event"
)

type contextAwareHandler struct {
        event.HandlerBase
        stopSawCanceled      bool
        uninstallSawCanceled bool
}

func (h *contextAwareHandler) GetName() string { return "context-aware" }
func (h *contextAwareHandler) GetNetworkPlugins() []string { return []string{event.AnyNetworkPlugin} }
func (h *contextAwareHandler) Stop(ctx context.Context) error {
        h.stopSawCanceled = ctx.Err() == context.Canceled
        return ctx.Err()
}
func (h *contextAwareHandler) Uninstall(ctx context.Context) error {
        h.uninstallSawCanceled = ctx.Err() == context.Canceled
        return ctx.Err()
}

var _ event.Handler = &contextAwareHandler{}

func mustContain(err error, want string) {
        if err == nil || !strings.Contains(err.Error(), want) {
                panic("expected error containing " + want)
        }
}

func main() {
        handler := &contextAwareHandler{}
        registry, err := event.NewRegistry(context.Background(), "repro", event.AnyNetworkPlugin, handler)
        if err != nil {
                panic(err)
        }

        ctx, cancel := context.WithCancel(context.Background())
        cancel()

        mustContain(registry.StopHandlers(ctx), "context canceled")
        if !handler.stopSawCanceled {
                panic("Stop did not receive canceled context")
        }

        mustContain(registry.Uninstall(ctx), "context canceled")
        if !handler.uninstallSawCanceled {
                panic("Uninstall did not receive canceled context")
        }
}
EOF
